def sumar_listas(lista_a, lista_b):
    if len(lista_a) != len(lista_b):
        raise ValueError("Las listas no tienen la misma longitud")
    resultado = []
    for x, y in zip(lista_a, lista_b):
        resultado.append(x + y)
    return resultado
